// TC25: multiple errors (distance negative, invalid packingService)
// input: { movingType: 'local', homeSize: 'studio', distance: -5, hasPiano: false, packingService: 'extra', storageNeeded: false }
// output: { error: "Distance must be greater than 0.; Invalid packing service." }

// === CALCULATOR ===
const calculator = {
  /**
   * Validates all inputs and returns { valid, errors }.
   * @param {Object} inputs
   * @returns {{ valid: boolean, errors: string[] }}
   */
  validate(inputs) {
    const errors = [];
    const validMovingTypes = ['local', 'longDistance', 'international'];
    const validHomeSizes = ['studio', '1BR', '2BR', '3BR', '4BR+'];
    const validPackingServices = ['self', 'partial', 'full'];

    // movingType
    if (!inputs.movingType) {
      errors.push('Moving type is required.');
    } else if (!validMovingTypes.includes(inputs.movingType)) {
      errors.push('Invalid moving type.');
    }

    // homeSize
    if (!inputs.homeSize) {
      errors.push('Home size is required.');
    } else if (!validHomeSizes.includes(inputs.homeSize)) {
      errors.push('Invalid home size.');
    }

    // distance
    if (typeof inputs.distance !== 'number' || isNaN(inputs.distance) || !isFinite(inputs.distance)) {
      errors.push('Distance must be a positive number.');
    } else if (inputs.distance <= 0) {
      errors.push('Distance must be greater than 0.');
    }

    // hasPiano
    if (typeof inputs.hasPiano !== 'boolean') {
      errors.push('hasPiano must be a boolean.');
    }

    // packingService
    if (!inputs.packingService) {
      errors.push('Packing service is required.');
    } else if (!validPackingServices.includes(inputs.packingService)) {
      errors.push('Invalid packing service.');
    }

    // storageNeeded
    if (typeof inputs.storageNeeded !== 'boolean') {
      errors.push('storageNeeded must be a boolean.');
    }

    return { valid: errors.length === 0, errors };
  },

  /**
   * Calculates total cost and breakdown.
   * Returns { total, breakdown } on success, or { error } on validation failure.
   * @param {Object} inputs
   * @returns {{ total: number, breakdown: Object } | { error: string }}
   */
  calculate(inputs) {
    const validation = this.validate(inputs);
    if (!validation.valid) {
      return { error: validation.errors.join('; ') };
    }

    // Base price lookup
    const basePrices = {
      local: { studio: 500, '1BR': 800, '2BR': 1200, '3BR': 1800, '4BR+': 2500 },
      longDistance: { studio: 1500, '1BR': 2500, '2BR': 3500, '3BR': 5000, '4BR+': 7000 },
      international: { studio: 5000, '1BR': 8000, '2BR': 12000, '3BR': 18000, '4BR+': 25000 },
    };

    const base = basePrices[inputs.movingType][inputs.homeSize];
    let distanceSurcharge = 0;

    if (inputs.movingType === 'longDistance') {
      const extraMiles = Math.max(0, inputs.distance - 500);
      distanceSurcharge = extraMiles * 1.5;
    } else if (inputs.movingType === 'international') {
      const extraMiles = Math.max(0, inputs.distance - 2000);
      distanceSurcharge = extraMiles * 2.5;
    }
    // local: no distance surcharge

    let packingSurcharge = 0;
    if (inputs.packingService === 'partial') {
      packingSurcharge = base * 0.2;
    } else if (inputs.packingService === 'full') {
      packingSurcharge = base * 0.4;
    }

    const pianoSurcharge = inputs.hasPiano ? 500 : 0;
    const storageSurcharge = inputs.storageNeeded ? 1000 : 0;

    const total = base + distanceSurcharge + packingSurcharge + pianoSurcharge + storageSurcharge;

    const breakdown = {
      base,
      distanceSurcharge,
      packingSurcharge,
      pianoSurcharge,
      storageSurcharge,
    };

    return { total, breakdown };
  },

  /**
   * Formats a number as USD currency string.
   * @param {number} amount
   * @returns {string}
   */
  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  },

  /**
   * Resets calculator state (returns default empty inputs).
   * @returns {Object}
   */
  reset() {
    return {
      movingType: '',
      homeSize: '',
      distance: '',
      hasPiano: false,
      packingService: 'self',
      storageNeeded: false,
    };
  },

  /**
   * Saves data to localStorage under the given key.
   * @param {string} key
   * @param {*} data
   */
  saveToLocalStorage(key, data) {
    try {
      const serialized = JSON.stringify(data);
      localStorage.setItem(key, serialized);
    } catch (err) {
      console.error('Failed to save to localStorage', err);
    }
  },

  /**
   * Loads data from localStorage by key, or returns null.
   * @param {string} key
   * @returns {*|null}
   */
  loadFromLocalStorage(key) {
    try {
      const stored = localStorage.getItem(key);
      if (stored) {
        return JSON.parse(stored);
      }
      return null;
    } catch (err) {
      console.error('Failed to load from localStorage', err);
      return null;
    }
  },
};
